import { useState, useCallback, useRef } from "react"
import { createFileRoute, useNavigate, useLocation } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { CountdownTimer } from "@/components/countdown-timer"
import { useSubmitExam } from "@/hooks/use-exams"
import type { StartExamResponse } from "@/hooks/use-exams"
import { cn } from "@/lib/utils"

/** 从 router location state 取出的考试数据 */
interface TakeExamState {
  recordId: number
  questions: StartExamResponse["questions"]
  startTime: string
  timeLimitMin: number
  examTitle: string
}

const OPTION_KEYS = ["A", "B", "C", "D"] as const

export const Route = createFileRoute("/_layout/exams/$id/take")({
  component: TakeExamPage,
})

function TakeExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const examId = Number(id)

  // 从 location state 获取考试数据
  const location = useLocation()
  const locationState = (location.state ?? {}) as Partial<TakeExamState>

  console.log("[lbl][TakeExamPage] location:", location)
  console.log("[lbl][TakeExamPage] location.state:", location.state)
  console.log("[lbl][TakeExamPage] window.history.state:", window.history.state)

  const recordId = locationState.recordId
  const questions = locationState.questions
  const startTime = locationState.startTime
  const timeLimitMin = locationState.timeLimitMin ?? 0
  const examTitle = locationState.examTitle ?? ""

  console.log("[lbl][TakeExamPage] recordId:", recordId, "questions?.length:", questions?.length)

  // 没有考试数据时跳回详情页
  if (!recordId || !questions?.length) {
    console.warn("[lbl][TakeExamPage] 缺少考试数据，redirect 回详情页", { recordId, questionsLen: questions?.length })
    navigate({ to: `/exams/${examId}`, replace: true })
    return null
  }

  return (
    <TakeExamContent
      examId={examId}
      recordId={recordId}
      questions={questions}
      startTime={startTime!}
      timeLimitMin={timeLimitMin}
      examTitle={examTitle}
    />
  )
}

interface TakeExamContentProps {
  examId: number
  recordId: number
  questions: StartExamResponse["questions"]
  startTime: string
  timeLimitMin: number
  examTitle: string
}

function TakeExamContent({
  examId,
  recordId,
  questions,
  startTime,
  timeLimitMin,
  examTitle,
}: TakeExamContentProps) {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const submitMutation = useSubmitExam()

  const [currentIndex, setCurrentIndex] = useState(0)
  const [answers, setAnswers] = useState<Record<number, string>>({})
  const [showConfirm, setShowConfirm] = useState(false)
  const submittingRef = useRef(false)

  const currentQuestion = questions[currentIndex]

  const handleSelectAnswer = (questionId: number, answer: string) => {
    setAnswers((prev) => ({ ...prev, [questionId]: answer }))
  }

  const doSubmit = useCallback(() => {
    // 防止重复提交（超时 + 手动同时触发）
    if (submittingRef.current) return
    submittingRef.current = true

    const answerList = questions.map((q) => ({
      questionId: q.id,
      answer: answers[q.id] ?? "",
    }))

    submitMutation.mutate(
      { examId, recordId, answers: answerList },
      {
        onSuccess: (res) => {
          toast.success(
            t("exam.submitSuccess", { score: res.score }),
          )
          navigate({ to: `/records/${recordId}`, replace: true })
        },
        onError: (err) => {
          toast.error(err.message)
          submittingRef.current = false
        },
      },
    )
  }, [answers, examId, navigate, questions, recordId, submitMutation, t])

  const handleTimeUp = useCallback(() => {
    toast.warning(t("exam.timeUp"))
    doSubmit()
  }, [doSubmit, t])

  const handleConfirmSubmit = () => {
    setShowConfirm(false)
    doSubmit()
  }

  const answeredCount = Object.keys(answers).length

  return (
    <div className="mx-auto max-w-3xl space-y-4">
      {/* 顶部栏：标题 + 倒计时 */}
      <div className="flex items-center justify-between rounded-lg border p-4">
        <h2 className="truncate text-lg font-semibold">{examTitle}</h2>
        {timeLimitMin > 0 && (
          <CountdownTimer
            startTime={startTime}
            timeLimitMin={timeLimitMin}
            onTimeUp={handleTimeUp}
          />
        )}
      </div>

      {/* 题目区域 */}
      <div className="rounded-lg border p-6 space-y-6">
        {/* 题号 */}
        <div className="text-sm text-muted-foreground">
          {t("exam.questionProgress", {
            current: currentIndex + 1,
            total: questions.length,
          })}
        </div>

        {/* 题目内容 */}
        <p className="text-base font-medium whitespace-pre-wrap">
          {currentQuestion.content}
        </p>

        {/* 选项 */}
        <RadioGroup
          value={answers[currentQuestion.id] ?? ""}
          onValueChange={(val) =>
            handleSelectAnswer(currentQuestion.id, val)
          }
          className="space-y-3"
        >
          {OPTION_KEYS.map((key) => {
            const optionField = `option${key}` as keyof typeof currentQuestion
            const optionText = currentQuestion[optionField] as string
            return (
              <div key={key} className="flex items-center gap-3">
                <RadioGroupItem value={key} id={`option-${key}`} />
                <Label
                  htmlFor={`option-${key}`}
                  className="cursor-pointer text-sm"
                >
                  {key}. {optionText}
                </Label>
              </div>
            )
          })}
        </RadioGroup>
      </div>

      {/* 底部导航 */}
      <div className="flex items-center justify-between">
        <div className="flex gap-2">
          <Button
            variant="outline"
            disabled={currentIndex <= 0}
            onClick={() => setCurrentIndex((i) => i - 1)}
          >
            {t("exam.prevQuestion")}
          </Button>
          <Button
            variant="outline"
            disabled={currentIndex >= questions.length - 1}
            onClick={() => setCurrentIndex((i) => i + 1)}
          >
            {t("exam.nextQuestion")}
          </Button>
        </div>
        <Button onClick={() => setShowConfirm(true)}>
          {t("common.submit")} ({answeredCount}/{questions.length})
        </Button>
      </div>

      {/* 题号网格 */}
      <div className="rounded-lg border p-4">
        <div className="flex flex-wrap gap-2">
          {questions.map((q, idx) => {
            const isAnswered = !!answers[q.id]
            const isCurrent = idx === currentIndex
            return (
              <button
                key={q.id}
                type="button"
                className={cn(
                  "flex h-8 w-8 items-center justify-center rounded text-sm font-medium transition-colors",
                  isAnswered && "bg-primary text-primary-foreground",
                  !isAnswered && !isCurrent && "bg-muted text-muted-foreground",
                  isCurrent && "ring-2 ring-primary ring-offset-1",
                )}
                onClick={() => setCurrentIndex(idx)}
              >
                {idx + 1}
              </button>
            )
          })}
        </div>
      </div>

      {/* 提交确认弹窗 */}
      <Dialog open={showConfirm} onOpenChange={setShowConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("exam.confirmSubmitTitle")}</DialogTitle>
            <DialogDescription>
              {t("exam.confirmSubmitDesc", {
                answered: answeredCount,
                total: questions.length,
              })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowConfirm(false)}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleConfirmSubmit}
              disabled={submitMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
